 const[favorites,setFavorites]=useState<Favorite[]>(storedFavorites),[settingsOpen,setSettingsOpen]=useState(false),[settingsSection,setSettingsSection]=useState<SettingsSection>('view'),[locationTracking,setLocationTracking]=useState(storedLocationTracking),[ensembleRequested,setEnsembleRequested]=useState(false),[layoutMode,setLayoutModeState]=useState<LayoutMode>(initializedLayoutMode),[layoutRevision,setLayoutRevision]=useState(0),[clockTick,setClockTick]=useState(()=>Date.now());
