        <pattern id="freezingDrizzlePattern" width="7" height="7" patternUnits="userSpaceOnUse"><rect width="7" height="7" fill="#75c9ff"/><path d="M0 7L7 0" stroke="#e9fbff" strokeWidth="1.2"/><circle cx="1.6" cy="1.6" r=".8" fill="#fff"/></pattern>
