        <pattern id="snowGrainsPattern" width="8" height="8" patternUnits="userSpaceOnUse"><rect width="8" height="8" fill="#dce9ff"/><rect x="1.5" y="1.5" width="1.7" height="1.7" rx=".3" fill="#fff"/><rect x="5" y="4.8" width="1.7" height="1.7" rx=".3" fill="#fff"/></pattern>
