       {sunriseX!==null&&<g pointerEvents="none"><line x1={sunriseX} x2={sunriseX} y1="0" y2={nightBottom} stroke="#7f91ad" strokeWidth="1" opacity="0.42" strokeDasharray="4 4"/><text x={sunriseX+5} y={timeY-5} textAnchor="start" fontSize={smallFont} fill="currentColor" opacity="0.68">↗ {sunriseLabel}</text></g>}
       {sunsetX!==null&&<g pointerEvents="none"><line x1={sunsetX} x2={sunsetX} y1="0" y2={nightBottom} stroke="#7f91ad" strokeWidth="1" opacity="0.42" strokeDasharray="4 4"/><text x={sunsetX-5} y={timeY-5} textAnchor="end" fontSize={smallFont} fill="currentColor" opacity="0.68">{sunsetLabel} ↘</text></g>}
